import{_ as a,o as i,c as s,a2 as t}from"./chunks/framework.tNPPebLH.js";const u=JSON.parse('{"title":"文档站维护","description":"","frontmatter":{},"headers":[],"relativePath":"site-maintenance.md","filePath":"site-maintenance.md","lastUpdated":1783841449000}'),d={name:"site-maintenance.md"};function l(n,e,o,c,r,h){return i(),s("div",null,[...e[0]||(e[0]=[t(`<h1 id="文档站维护" tabindex="-1">文档站维护 <a class="header-anchor" href="#文档站维护" aria-label="Permalink to &quot;文档站维护&quot;">​</a></h1><p>PetPack 文档站使用 VitePress 构建。源码和发布产物分开管理：</p><table tabindex="0"><thead><tr><th>分支</th><th>用途</th></tr></thead><tbody><tr><td><code>main</code></td><td>产品源码、README、文档源码和工作流</td></tr><tr><td><code>gh-pages</code></td><td>GitHub Actions 生成的静态站点，不作为开发分支</td></tr></tbody></table><h2 id="文档入口" tabindex="-1">文档入口 <a class="header-anchor" href="#文档入口" aria-label="Permalink to &quot;文档入口&quot;">​</a></h2><ul><li><code>README.md</code>：面向 GitHub 访客的项目概览、下载和快速入口；</li><li><code>docs/index.md</code>：文档站首页；</li><li><code>docs/getting-started.md</code>：第一次使用；</li><li><code>docs/user-guide.md</code>：完整功能和交互；</li><li><code>docs/PET_FORMATS.md</code>：宠物作者格式规范；</li><li><code>docs/CROSS_PLATFORM.md</code>：跨平台分发和 Release；</li><li><code>docs/DOCKER.md</code>：Web Studio 部署；</li><li><code>docs/development.md</code>：开发、测试和构建；</li><li><code>docs/troubleshooting.md</code>：用户排错。</li></ul><h2 id="发布规则" tabindex="-1">发布规则 <a class="header-anchor" href="#发布规则" aria-label="Permalink to &quot;发布规则&quot;">​</a></h2><p><code>.github/workflows/docs.yml</code> 在文档、README、文档依赖或自身变化时运行：</p><ul><li>Pull Request：只构建并验证，不发布；</li><li>推送 <code>main</code>：构建后强制更新 <code>gh-pages</code>；</li><li>手动触发：按当前分支执行同一流程。</li></ul><p>GitHub Pages 应配置为从 <code>gh-pages</code> 分支根目录发布。不要直接向该分支提交文档源码。</p><h2 id="本地预览" tabindex="-1">本地预览 <a class="header-anchor" href="#本地预览" aria-label="Permalink to &quot;本地预览&quot;">​</a></h2><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ci</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs:dev</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>生产构建：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs:build</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>部署基路径由 <code>DOCS_BASE</code> 控制。仓库 Pages 使用 <code>/petpack/</code>，本地开发默认使用 <code>/</code>。</p><h2 id="内容维护原则" tabindex="-1">内容维护原则 <a class="header-anchor" href="#内容维护原则" aria-label="Permalink to &quot;内容维护原则&quot;">​</a></h2><ul><li>README 保持面向新用户，不复制完整手册；</li><li>下载安装表必须和 Actions 真实产物名称一致；</li><li>版本功能、安装包和 SHA-256 以 GitHub Release 为准；</li><li>不把 token、证书、API Key 或本地绝对路径写入公开文档；</li><li>UI 文案变化时同步更新快速开始和使用手册；</li><li>平台限制必须明确区分“已原生测试”和“仅配置构建”。</li></ul>`,16)])])}const b=a(d,[["render",l]]);export{u as __pageData,b as default};
